import{_ as t,o,c as a,a4 as r}from"./chunks/framework.EG5hAXdg.js";const p=JSON.parse('{"title":"Budgeting","description":"This page give some advice on how to budget for lab costs in HUNT Cloud.","frontmatter":{"title":"Budgeting","category":"Prices","permalink":"/administer-science/prices/budgeting","outline":"2-3","description":"This page give some advice on how to budget for lab costs in HUNT Cloud."},"headers":[],"relativePath":"administer-science/prices/budgeting.md","filePath":"administer-science/prices/budgeting.md"}'),i={name:"administer-science/prices/budgeting.md"};function n(s,e,c,l,d,u){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="budgeting" tabindex="-1">Budgeting <a class="header-anchor" href="#budgeting" aria-label="Permalink to &quot;Budgeting&quot;">​</a></h1><p><strong>There are a few key points to consider as you plan the budget for your work.</strong></p><nav class="table-of-contents"><ul><li><a href="#when-will-you-need-resources">When will you need resources</a></li><li><a href="#allow-for-costs-to-increase-over-time">Allow for costs to increase over time</a></li><li><a href="#data-lives-longer-than-the-project-funding">Data lives longer than the project funding</a></li></ul></nav><p>First, It may be difficult to translate your experiments and ideas into concrete machine sizes and storage volumes. Don&#39;t hesitate to <a href="/contact">contact us</a> for dialogues on cost estimates. We are more than happy to share our experience from similar activities in your field, and to help with estimated for grants and other funding sources.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Check our <a href="/administer-science/prices/calculator">price estimator</a> and <a href="/administer-science/prices/examples">price examples</a> to aid your budgeting effort.</p></div><h3 id="when-will-you-need-resources" tabindex="-1">When will you need resources <a class="header-anchor" href="#when-will-you-need-resources" aria-label="Permalink to &quot;When will you need resources&quot;">​</a></h3><p>You will typically have different activity phases in your project. Some require more computational resource, others less. Note that you can update your lab resources throughout your lab lifetime.</p><p>This can be an effective way to keep costs under control, and may allow differentiated compute costs across your budget period. For example, you may use your initial time to collect data, then you may have a period with intense analysis, and at the end spend most of your time writing up your papers.</p><p>If you can afford to have resources available for your team throughout the year, it might be most effective to do so. However, if your team works in bursts of high activity, followed by low activity for at least a month, you should consider to budget with turning resources up and down.</p><h3 id="allow-for-costs-to-increase-over-time" tabindex="-1">Allow for costs to increase over time <a class="header-anchor" href="#allow-for-costs-to-increase-over-time" aria-label="Permalink to &quot;Allow for costs to increase over time&quot;">​</a></h3><p>When you plan for a project that last 3-5 years, you should consider to allow for increased computational costs.</p><p>Computer equipment do typically increase faster than the consume index. In addition, your experiment may become more advanced as you acquire new computational skills get access to more data. Such, if possible, it may be good to allow for cost to increase during your project period.</p><p>Also, projects tend to take longer than planned, and extensions typically don&#39;t come with additional funds to cover your lab costs. Such, we recommend that to allow for a buffer of your expected costs.</p><h3 id="data-lives-longer-than-the-project-funding" tabindex="-1">Data lives longer than the project funding <a class="header-anchor" href="#data-lives-longer-than-the-project-funding" aria-label="Permalink to &quot;Data lives longer than the project funding&quot;">​</a></h3><p>Make sure to budget for data archiving after the project ends.</p><p>For example, your might be required to store data for five years or more by ethical committees, typically after your funding has ended. Furthermore, you might be asked to make data or metadata available according to open science-principles, or to return it to the data controller. In either case, caring for your data after the project period must be reflected in your budget.</p>',16)])])}const m=t(i,[["render",n]]);export{p as __pageData,m as default};
